const MekongStore={state:{customers:{data: [],loading: false,lastFetch: null},leads:{data: [],loading: false,lastFetch: null},posts:{data: [],loading: false,lastFetch: null},invoices:{data: [],loading: false,lastFetch: null},deals:{data: [],loading: false,lastFetch: null}},subscribers:{},config:{cacheTimeout: 5*60*1000,persistKeys: ['customers','leads'],debug: false},get(key){return this.state[key]||{data: [],loading: false,lastFetch: null};},getData(key){return this.state[key]?.data||[];},isStale(key){const state=this.state[key];if(!state?.lastFetch)return true;return Date.now()-state.lastFetch>this.config.cacheTimeout;},set(key,data,options={}){this._ensureState(key);this.state[key].data=data;this.state[key].loading=false;this.state[key].lastFetch=Date.now();this._persist(key);if(!options.silent){this._notify(key,'set',data);}this._log(`Set ${key}:`,data.length,'items');},setLoading(key,loading){if(this.state[key]){this.state[key].loading=loading;this._notify(key,'loading',loading);}},add(key,item){if(!this.state[key])return;this.state[key].data.unshift(item);this._updateMetaAndNotify(key,'add',item);},update(key,id,updates){if(!this.state[key])return;const index=this.state[key].data.findIndex(item=>item.id===id);if(index!==-1){this.state[key].data[index]={...this.state[key].data[index],...updates};this._updateMetaAndNotify(key,'update',{id,updates});}},remove(key,id){if(!this.state[key])return;this.state[key].data=this.state[key].data.filter(item=>item.id!==id);this._updateMetaAndNotify(key,'remove',{id});},_updateMetaAndNotify(key,action,payload){this.state[key].lastFetch=Date.now();this._persist(key);this._notify(key,action,payload);this._log(`${action}on ${key}`);},_ensureState(key){if(!this.state[key]){this.state[key]={data: [],loading: false,lastFetch: null};}},subscribe(key,callback){if(!this.subscribers[key]){this.subscribers[key]=[];}this.subscribers[key].push(callback);this._log(`Subscribed to ${key}`);return()=>{if(this.subscribers[key]){this.subscribers[key]=this.subscribers[key].filter(cb=>cb!==callback);}};},_notify(key,action,payload){const notifyList=(list)=>{if(!list)return;list.forEach(cb=>{try{cb(action,payload,key);}catch(err){}});};notifyList(this.subscribers[key]);notifyList(this.subscribers['*']);window.dispatchEvent(new CustomEvent('mekong:store:change',{detail:{key,action,payload}}));},_persist(key){if(!this.config.persistKeys.includes(key))return;try{const data=this.state[key];localStorage.setItem(`mekong_store_${key}`,JSON.stringify({data: data.data,lastFetch: data.lastFetch}));}catch(err){}},_restore(key){try{const stored=localStorage.getItem(`mekong_store_${key}`);if(stored){const parsed=JSON.parse(stored);this.state[key]={data: parsed.data||[],loading: false,lastFetch: parsed.lastFetch||null};this._log(`Restored ${key}from cache:`,parsed.data?.length||0,'items');return true;}}catch(err){}return false;},clearCache(){this.config.persistKeys.forEach(key=>{localStorage.removeItem(`mekong_store_${key}`);});this._log('Cache cleared');},init(){this.config.persistKeys.forEach(key=>{this._restore(key);});this._log('Store initialized');},_log(...args){if(this.config.debug){}},enableDebug(){this.config.debug=true;}};const ENTITY_MAP={customers: 'customers',contacts: 'leads',scheduled_posts: 'posts',invoices: 'invoices'};const DataSync={async fetch(entity,filters={}){if(!MekongStore.isStale(entity)&&MekongStore.getData(entity).length>0){return{data: MekongStore.getData(entity),fromCache: true};}MekongStore.setLoading(entity,true);try{let result;switch(entity){case 'customers': result=await AdminAPI.loadCustomers(filters);break;case 'leads': result=await this._fetchLeads(filters);break;case 'posts': result=await AdminAPI.loadPosts(filters);break;case 'invoices': result=await this._fetchInvoices(filters);break;default: throw new Error(`Unknown entity: ${entity}`);}if(!result.error){MekongStore.set(entity,result.data);return{data: result.data,fromCache: false};}else{throw result.error;}}catch(err){MekongStore.setLoading(entity,false);return{data: MekongStore.getData(entity),error: err};}},async mutate(entity,action,data){try{let result;switch(entity){case 'customers': result=await this._mutateCustomer(action,data);break;case 'posts': result=await this._mutatePost(action,data);break;default: throw new Error(`Unknown entity for mutation: ${entity}`);}if(!result.error){if(action==='save'){if(data.id){MekongStore.update(entity,data.id,result.data);}else{MekongStore.add(entity,result.data);}}else if(action==='delete'){MekongStore.remove(entity,data.id||data);}else if(action==='updateStatus'){MekongStore.update(entity,data.id,{status: data.status});}return{success: true,data: result.data};}else{return{success: false,error: result.error};}}catch(err){return{success: false,error: err};}},handleRealtimeUpdate(table,payload){const entity=ENTITY_MAP[table];if(!entity)return;switch(payload.eventType){case 'INSERT': MekongStore.add(entity,payload.new);break;case 'UPDATE': MekongStore.update(entity,payload.new.id,payload.new);break;case 'DELETE': MekongStore.remove(entity,payload.old.id);break;}},async _fetchLeads(filters){const client=window.SupabaseAPI?.getClient();if(!client)return{error: 'Not initialized',data: []};let query=client.from('contacts').select('*').order('created_at',{ascending: false});if(filters.limit)query=query.limit(filters.limit);return await query;},async _fetchInvoices(filters){const client=window.SupabaseAPI?.getClient();if(!client)return{error: 'Not initialized',data: []};let query=client.from('invoices').select('*').order('created_at',{ascending: false});if(filters.limit)query=query.limit(filters.limit);return await query;},async _mutateCustomer(action,data){switch(action){case 'save': return await AdminAPI.saveCustomer(data);case 'delete': return await AdminAPI.deleteCustomer(data.id||data);case 'updateStatus': return await AdminAPI.updateCustomerStatus(data.id,data.status);default: throw new Error(`Unknown action: ${action}`);}},async _mutatePost(action,data){switch(action){case 'save': return await AdminAPI.savePost(data);case 'delete': return await AdminAPI.deletePost(data.id||data);case 'updateStatus': return await AdminAPI.updatePostStatus(data.id,data.status);default: throw new Error(`Unknown action: ${action}`);}}};window.MekongStore=MekongStore;window.DataSync=DataSync;document.addEventListener('DOMContentLoaded',()=>{MekongStore.init();});